    /// <summary>Иконки тех эмодзи, что встречались в старых сохранениях.</summary>
    private static readonly IReadOnlyDictionary<string, string> LegacyEmojiToIconName = new Dictionary<string, string>
    {
        ["⚓"] = "description", ["👤"] = "person", ["🎭"] = "mood", ["💭"] = "cloud",
        ["❤️"] = "favorite", ["🗳"] = "public", ["🗣"] = "mic", ["👥"] = "group",
        ["🎬"] = "flag", ["🌊"] = "sailing", ["📝"] = "notes", ["✦"] = "star", ["🚂"] = "bolt"
    };

    /// <summary>
    /// Возвращает корректное имя иконки: известные имена проходят как есть,
    /// эмодзи из старых сохранений получают замену, всё прочее — звезда.
    /// </summary>
    public static string ResolveIconName(string storedIconValue)
    {
        if (IconPathsByName.ContainsKey(storedIconValue))
        {
            return storedIconValue;
        }

        return LegacyEmojiToIconName.GetValueOrDefault(storedIconValue, "star");
    }
